import Bowser from 'bowser';

declare enum BrowserName {
    CHROME = "Chrome",
    FIREFOX = "Firefox",
    EDGE = "Microsoft Edge",
    SAFARI = "Safari"
}
declare enum OSName {
    WINDOWS = "Windows",
    MAC = "macOS",
    LINUX = "Linux"
}
declare class BrowserInfo {
    private static browser;
    static getBrowserDetails(): Bowser.Parser.BrowserDetails;
    static getOSDetails(): Bowser.Parser.OSDetails;
    static getPlatformDetails(): Bowser.Parser.PlatformDetails;
    static getEngineDetails(): Bowser.Parser.EngineDetails;
    static isChrome(): boolean;
    static isFirefox(): boolean;
    static isEdge(): boolean;
    static isSafari(): boolean;
    static isWindows(): boolean;
    static isMac(): boolean;
    static isLinux(): boolean;
    static isVersionGreaterThan(version: string): boolean;
    static isVersionGreaterThanOrEqualTo(version: string): boolean;
    static isVersionLessThan(version: string): boolean;
    static isVersionLessThanOrEqualTo(version: string): boolean;
    static isSubVersionOf(version: string): boolean;
}

declare class CpuInfo {
    static getNumLogicalCores(): number | undefined;
}

type PressureSource = 'cpu';
type PressureState = 'nominal' | 'fair' | 'serious' | 'critical';
interface PressureRecord {
    source: string;
    state: PressureState;
    time: number;
}
interface PressureObserver {
    observe(source: PressureSource): Promise<void>;
    unobserve(source: PressureSource): void;
    disconnect(): void;
    takeRecords(): PressureRecord[];
}
declare global {
    interface Window {
        PressureObserver?: PressureObserver;
    }
}
declare enum SystemInfoEvents {
    CpuPressureStateChange = "cpu-pressure-state-change"
}
declare class SystemInfo {
    static isPressureObserverSupported(): boolean;
    static getCpuPressure(): PressureState | undefined;
    static onCpuPressureChange(callback: (state: PressureState) => void): void;
    static offCpuPressureChange(callback: (state: PressureState) => void): void;
    static getNumLogicalCores(): number | undefined;
}

declare enum CapabilityState {
    NOT_CAPABLE = "not capable",
    CAPABLE = "capable",
    UNKNOWN = "unknown"
}
declare class WebCapabilities {
    static isCapableOfBackgroundNoiseRemoval(): CapabilityState;
    static isCapableOfVirtualBackground(): CapabilityState;
    static isCapableOfReceiving1080pVideo(): CapabilityState;
    static isCapableOfSending1080pVideo(): CapabilityState;
    static isCapableOfReceivingVideoCodec(mimeType: RTCRtpCodecCapability['mimeType']): CapabilityState;
    static supportsEncodedStreamTransforms(): CapabilityState;
    static supportsRTCPeerConnection(): CapabilityState;
    static supportsEncodingCodec(): CapabilityState;
}

export { BrowserInfo, BrowserName, CapabilityState, CpuInfo, OSName, PressureSource, PressureState, SystemInfo, SystemInfoEvents, WebCapabilities };
